    98→func (srv *Server) EvaluationSnapshotNamespace(ctx context.Context, r *evaluation.EvaluationNamespaceSnapshotRequest) (*evaluation.EvaluationNamespaceSnapshot, error) {
    99→	var (
   100→		namespaceKey = r.Key
   101→		reference    = r.Reference
   102→		resp         = &evaluation.EvaluationNamespaceSnapshot{
   103→			Namespace: &evaluation.EvaluationNamespace{ // TODO: should we get from store?
   104→				Key: namespaceKey,
   105→			},
   106→			Flags: make([]*evaluation.EvaluationFlag, 0),
   107→		}
   108→		remaining              = true
   109→		nextPage               string
   110→		segments               = make(map[string]*evaluation.EvaluationSegment)
   111→		supportedServerVersion = grpc_middleware.FliptAcceptServerVersionFromContext(ctx)
   112→	)
   113→
   114→	//  flags/variants in batches
   115→	for remaining {
   116→		res, err := srv.store.ListFlags(
   117→			ctx,
   118→			storage.ListWithOptions(
   119→				storage.NewNamespace(namespaceKey, storage.WithReference(reference)),
   120→				storage.ListWithQueryParamOptions[storage.NamespaceRequest](storage.WithPageToken(nextPage)),
   121→			),
   122→		)
   123→		if err != nil {
   124→			return nil, fmt.Errorf("getting flags: %w", err)
   125→		}
   126→
   127→		flags := res.Results
   128→		nextPage = res.NextPageToken
   129→		remaining = nextPage != ""
   130→
   131→		for _, f := range flags {
   132→			flag := &evaluation.EvaluationFlag{
   133→				Key:         f.Key,
   134→				Name:        f.Name,
   135→				Description: f.Description,
   136→				Enabled:     f.Enabled,
   137→				Type:        toEvaluationFlagType(f.Type),
   138→				CreatedAt:   f.CreatedAt,
   139→				UpdatedAt:   f.UpdatedAt,
   140→			}
   141→
   142→			flagKey := storage.NewResource(namespaceKey, f.Key, storage.WithReference(reference))
   143→			if f.Type == flipt.FlagType_VARIANT_FLAG_TYPE {
   144→				rules, err := srv.store.GetEvaluationRules(ctx, flagKey)
   145→				if err != nil {
   146→					return nil, fmt.Errorf("getting rules for flag %q: %w", f.Key, err)
   147→				}
   148→
   149→				for _, r := range rules {
   150→					rule := &evaluation.EvaluationRule{
   151→						Id:              r.ID,
   152→						Rank:            r.Rank,
   153→						SegmentOperator: toEvaluationSegmentOperator(r.SegmentOperator),
   154→					}
   155→
   156→					for _, s := range r.Segments {
   157→						// optimization: reuse segment if already seen
   158→						if ss, ok := segments[s.SegmentKey]; ok {
   159→							rule.Segments = append(rule.Segments, ss)
   160→						} else {
   161→
   162→							ss := &evaluation.EvaluationSegment{
   163→								Key:       s.SegmentKey,
   164→								MatchType: toEvaluationSegmentMatchType(s.MatchType),
   165→							}
   166→
   167→							for _, c := range s.Constraints {
   168→								typ := toEvaluationConstraintComparisonType(c.Type)
   169→								// see: https://github.com/flipt-io/flipt/pull/2791
   170→								if typ == evaluation.EvaluationConstraintComparisonType_ENTITY_ID_CONSTRAINT_COMPARISON_TYPE {
   171→									if supportedServerVersion.LT(supportsEntityIdConstraintMinVersion) {
   172→										srv.logger.Warn("skipping `entity_id` constraint type to support older client; upgrade client to allow `entity_id` constraint type", zap.String("namespace", f.NamespaceKey), zap.String("flag", f.Key))
   173→										typ = evaluation.EvaluationConstraintComparisonType_UNKNOWN_CONSTRAINT_COMPARISON_TYPE
   174→									}
   175→								}
   176→
   177→								ss.Constraints = append(ss.Constraints, &evaluation.EvaluationConstraint{
   178→									Id:       c.ID,
   179→									Type:     typ,
   180→									Property: c.Property,
   181→									Operator: c.Operator,
   182→									Value:    c.Value,
   183→								})
   184→							}
   185→
   186→							segments[s.SegmentKey] = ss
   187→							rule.Segments = append(rule.Segments, ss)
   188→						}
   189→
   190→						distributions, err := srv.store.GetEvaluationDistributions(ctx, storage.NewID(r.ID, storage.WithReference(reference)))
   191→						if err != nil {
   192→							return nil, fmt.Errorf("getting distributions for rule %q: %w", r.ID, err)
   193→						}
   194→
   195→						// distributions for rule
   196→						for _, d := range distributions {
   197→							dist := &evaluation.EvaluationDistribution{
   198→								VariantId:         d.VariantID,
   199→								VariantKey:        d.VariantKey,
   200→								VariantAttachment: d.VariantAttachment,
   201→								Rollout:           d.Rollout,
   202→							}
   203→							rule.Distributions = append(rule.Distributions, dist)
   204→						}
   205→
   206→						flag.Rules = append(flag.Rules, rule)
   207→					}
   208→
   209→				}
   210→			}
   211→
   212→			if f.Type == flipt.FlagType_BOOLEAN_FLAG_TYPE {
   213→				rollouts, err := srv.store.GetEvaluationRollouts(ctx, flagKey)
   214→				if err != nil {
   215→					return nil, fmt.Errorf("getting rollout rules for flag %q: %w", f.Key, err)
   216→				}
   217→
   218→				for _, r := range rollouts {
   219→					rollout := &evaluation.EvaluationRollout{
   220→						Type: toEvaluationRolloutType(r.RolloutType),
   221→						Rank: r.Rank,
   222→					}
   223→
   224→					switch r.RolloutType {
   225→					case flipt.RolloutType_THRESHOLD_ROLLOUT_TYPE:
   226→						rollout.Rule = &evaluation.EvaluationRollout_Threshold{
   227→							Threshold: &evaluation.EvaluationRolloutThreshold{
   228→								Percentage: r.Threshold.Percentage,
   229→								Value:      r.Threshold.Value,
   230→							},
   231→						}
   232→
   233→					case flipt.RolloutType_SEGMENT_ROLLOUT_TYPE:
   234→						segment := &evaluation.EvaluationRolloutSegment{
   235→							Value:           r.Segment.Value,
   236→							SegmentOperator: toEvaluationSegmentOperator(r.Segment.SegmentOperator),
   237→						}
   238→
   239→						for _, s := range r.Segment.Segments {
   240→							// optimization: reuse segment if already seen
   241→							ss, ok := segments[s.SegmentKey]
   242→							if ok {
   243→								segment.Segments = append(segment.Segments, ss)
   244→								continue
   245→							}
   246→
   247→							ss = &evaluation.EvaluationSegment{
   248→								Key:       s.SegmentKey,
   249→								MatchType: toEvaluationSegmentMatchType(s.MatchType),
   250→							}
   251→
   252→							for _, c := range s.Constraints {
   253→								typ := toEvaluationConstraintComparisonType(c.Type)
   254→								// see: https://github.com/flipt-io/flipt/pull/2791
   255→								if typ == evaluation.EvaluationConstraintComparisonType_ENTITY_ID_CONSTRAINT_COMPARISON_TYPE {
   256→									if supportedServerVersion.LT(supportsEntityIdConstraintMinVersion) {
   257→										srv.logger.Warn("skipping `entity_id` constraint type to support older client; upgrade client to allow `entity_id` constraint type", zap.String("namespace", f.NamespaceKey), zap.String("flag", f.Key))
   258→										typ = evaluation.EvaluationConstraintComparisonType_UNKNOWN_CONSTRAINT_COMPARISON_TYPE
   259→									}
   260→								}
   261→
   262→								ss.Constraints = append(ss.Constraints, &evaluation.EvaluationConstraint{
   263→									Id:       c.ID,
   264→									Type:     typ,
   265→									Property: c.Property,
   266→									Operator: c.Operator,
   267→									Value:    c.Value,
   268→								})
   269→							}
   270→
   271→							segments[s.SegmentKey] = ss
   272→							segment.Segments = append(segment.Segments, ss)
   273→						}
   274→
   275→						rollout.Rule = &evaluation.EvaluationRollout_Segment{
   276→							Segment: segment,
   277→						}
   278→					}
   279→
   280→					flag.Rollouts = append(flag.Rollouts, rollout)
   281→				}
   282→			}
   283→
   284→			resp.Flags = append(resp.Flags, flag)
   285→		}
   286→	}
