#!/usr/bin/env python3
from collections import defaultdict, deque

# Direct dependencies: pkg -> set of packages it depends on
dependencies = {
    'internal/server/evaluation': {
        'errors',
        'internal/server/metrics',
        'internal/server/otel',
        'internal/storage',
        'rpc/flipt',
        'rpc/flipt/evaluation'
    },
    'internal/storage': {
        'internal/containers',
        'rpc/flipt'
    },
    'internal/server/metrics': {
        'internal/metrics'
    },
    'internal/server/otel': set(),
    'errors': set(),
    'rpc/flipt': {'errors'},
    'rpc/flipt/evaluation': set(),
    'internal/metrics': set(),
    'internal/containers': set(),
}

print("Direct dependencies:")
for pkg in sorted(dependencies.keys()):
    deps = dependencies[pkg]
    if deps:
        print(f"  {pkg} depends on: {sorted(deps)}")
    else:
        print(f"  {pkg} has no dependencies")

# For topological sort, we want to count how many dependencies each package has
# Initialize in_degree as the count of direct dependencies
in_degree = {}
for pkg in dependencies:
    in_degree[pkg] = len(dependencies[pkg])

print("\nInitial in-degree (number of dependencies):")
for pkg in sorted(in_degree.items()):
    print(f"  {pkg[0]}: {pkg[1]}")

# Process in topological order
result = []
processed = set()
queue = deque([pkg for pkg in in_degree if in_degree[pkg] == 0])

print(f"\nStarting with packages that have no dependencies: {sorted(queue)}")

while queue:
    # Sort by name for consistent ordering when there are ties
    pkg = queue.popleft()
    result.append(pkg)
    processed.add(pkg)

    # For each package that depends on this one, reduce its in-degree
    for other_pkg, other_deps in dependencies.items():
        if other_pkg in processed:
            continue
        if pkg in other_deps:
            in_degree[other_pkg] -= 1
            if in_degree[other_pkg] == 0:
                queue.append(other_pkg)

print("\nTopological Order (dependencies first, target last):")
for i, pkg in enumerate(result, 1):
    print(f"{i}. {pkg}")

print(f"\nVerification - 'internal/server/evaluation' is at position: {result.index('internal/server/evaluation') + 1}")

import json
with open("/workspace/submission.json", "w") as f:
    json.dump(result, f, indent=2)

print(f"\nWrote to /workspace/submission.json")
EOF
